BufferFormat.Format:
struct MeshData{
   uint submesh_start;
   uint submesh_count;

   uint meshlet_start;
   uint meshlet_vertice_start;
   uint meshlet_triangle_start;
                
   //bounding sphere structure
   float3 center;
   float radius; 
};

